import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"周边","description":"华南理工大学大学城校区周边去处的简介页面","frontmatter":{"lang":"zh-CN","title":"周边","description":"华南理工大学大学城校区周边去处的简介页面"},"headers":[],"relativePath":"infra/hemc/nearby.md","filePath":"infra/hemc/nearby.md","lastUpdated":1784896159000}`),a={name:`infra/hemc/nearby.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /infra/hemc/nearby.md for this page in Markdown format</div><h1 id="大学城周边" tabindex="-1">大学城周边 <a class="header-anchor" href="#大学城周边" aria-label="Permalink to “大学城周边”">​</a></h1><p>大学城校区周边主要的吃喝玩乐去处集中在<strong>南亭、北亭、贝岗、穗石</strong>四个城中村。其中贝岗村的 gogo 新天地是大学城最常去的商业综合体。</p><h2 id="餐饮与夜市" tabindex="-1">餐饮与夜市 <a class="header-anchor" href="#餐饮与夜市" aria-label="Permalink to “餐饮与夜市”">​</a></h2><h3 id="贝岗村-gogo-新天地" tabindex="-1">贝岗村 &amp; gogo 新天地 <a class="header-anchor" href="#贝岗村-gogo-新天地" aria-label="Permalink to “贝岗村 &amp; gogo 新天地”">​</a></h3><p>步行从 C 区出发约 15 分钟到达 gogo 新天地。这里有肯德基、麦当劳、萨莉亚等常见的连锁餐饮品牌，以及一点点、喜茶等奶茶店。</p><h3 id="穗石村" tabindex="-1">穗石村 <a class="header-anchor" href="#穗石村" aria-label="Permalink to “穗石村”">​</a></h3><p>穗石村离学校最近——从图书馆和 A1 教学楼之间的道路直行约 3 分钟出校门即达。主要餐饮有：</p><ul><li><strong>面食/饭类</strong>：震亚牛肉面、隆江猪脚饭</li><li><strong>正餐/聚餐</strong>：北调儿铜炉鸡锅、东北菜、武汉小炒、仙庙烧鸡、鸡公煲</li><li><strong>饮品</strong>：蜜雪冰城、茶百道、幸运咖</li><li>（更多店铺欢迎补充）</li></ul><blockquote><p>gogo 新天地与穗石村各有侧重：前者品牌连锁集中，适合逛街聚餐；后者胜在离校近、选择多样，是日常外食和夜宵的好去处。</p></blockquote><h2 id="日用采买与超市" tabindex="-1">日用采买与超市 <a class="header-anchor" href="#日用采买与超市" aria-label="Permalink to “日用采买与超市”">​</a></h2><h3 id="校内" tabindex="-1">校内 <a class="header-anchor" href="#校内" aria-label="Permalink to “校内”">​</a></h3><ul><li><strong>西亚兴安综合超市</strong>：位于校内生活区，一楼以食品和饮料为主，二楼有食品、文具以及少量就餐店铺。规模不大，但常用的生活用品和小零食基本齐全。</li><li><strong>全家便利店</strong>：位于 C10 楼下（麦当劳后面）。</li><li><strong>C10 楼下水果店</strong>：校内买水果的选项之一。</li></ul><h3 id="校外" tabindex="-1">校外 <a class="header-anchor" href="#校外" aria-label="Permalink to “校外”">​</a></h3><ul><li><strong>穗石村水果店</strong>：距离近，步行可达，是校内外出买水果最方便的选择。</li></ul><blockquote><p>大学城校区附近没有菜市场。如需买菜做饭，可考虑线上生鲜配送或前往周边大型超市。</p></blockquote><h2 id="租房与短租信息" tabindex="-1">租房与短租信息 <a class="header-anchor" href="#租房与短租信息" aria-label="Permalink to “租房与短租信息”">​</a></h2><p>大学城校区周边的城中村（南亭、北亭、贝岗、穗石）均有房源可供出租，适合考研备考、实习等需要短租或长租的情况。</p><blockquote><p>详细的租房经验（常见区域对比、租金水平、房东情况、防坑指南等）欢迎有相关经历的同学贡献补充。</p></blockquote><h2 id="交通接驳" tabindex="-1">交通接驳 <a class="header-anchor" href="#交通接驳" aria-label="Permalink to “交通接驳”">​</a></h2><h3 id="地铁" tabindex="-1">地铁 <a class="header-anchor" href="#地铁" aria-label="Permalink to “地铁”">​</a></h3><p>从生活区<strong>西一门</strong>出，左转至红绿灯处过马路即达<strong>大学城南站</strong>，非常便捷。可换乘以下线路：</p><ul><li><strong>7号线</strong>：可达广州南站、南村万博、汉溪长隆等商圈及交通枢纽</li><li><strong>4号线</strong>：可达万胜围站（换乘 8 号线）</li><li><strong>12号线</strong>：可达岛内及海珠区</li></ul><h3 id="共享单车" tabindex="-1">共享单车 <a class="header-anchor" href="#共享单车" aria-label="Permalink to “共享单车”">​</a></h3><p>校区内仅有<strong>共享单车</strong>，<strong>不允许骑电动车</strong>，也没有运营共享电动车。校内的哈啰和青桔共享单车可以骑出校外（非专属校园单车），适合骑至地铁站或大学城内各处。</p><h3 id="出岛交通" tabindex="-1">出岛交通 <a class="header-anchor" href="#出岛交通" aria-label="Permalink to “出岛交通”">​</a></h3><p>出岛以乘坐地铁（7号线、4号线、12号线）最为方便。另有少数公交线路可通过琶洲大桥、金光隧道等通往岛外，具体线路及运营情况请关注广州公交集团相关通知。</p><h2 id="休闲娱乐" tabindex="-1">休闲娱乐 <a class="header-anchor" href="#休闲娱乐" aria-label="Permalink to “休闲娱乐”">​</a></h2><ul><li><strong>gogo 新天地</strong>：大学城最全面的综合商圈，除餐饮外还有电影院、KTV、服装店等，是同学聚餐、逛街、看电影的首选。</li><li><strong>健身房</strong>：大学城体育中心有健身房可供选择；校内西亚兴安综合超市三楼也设有健身房，可进一步了解详情。</li><li><strong>中心湖公园</strong>：位于小谷围岛上的户外去处，适合周末及白天前往游玩。<strong>安全提示</strong>：建议结伴而行，尤其不建议晚上到内环跑步或到中心湖公园散步，注意人身安全。</li></ul>`,29)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};